is_prime = 入力 n に対し {
  もし n < 2 ならば {
    偽を返す
  }

  もし n == 2 ならば {
    真を返す
  }

  もし n % 2 == 0 ならば {
    偽を返す
  }

  i = 3 として {
    i * i <= n の間 {
