fix_spaces = 入力 text に対し {
    length = |text|
    result = []

    i = 0
    200回、くり返す {
        もし i が length より小さいならば、{
            char = text[i]
            もし char が 32 ならば、{  # space
                # Count consecutive spaces
                space_count = 1
                j = 和(i, 1)
                100回、くり返す {
                    もし j が length より小さいならば、{
                        もし text[j] が 32 ならば、{
                            space_countを増やす
                            jを増やす
                        }
                        そうでなければ {
                            j = length  # Exit loop
                        }
                    }
                }

                # Replace spaces based on count
                もし space_count が 2 以下 ならば、{
                    # Add underscores
                    k = 0
                    space_count回、くり返す {
                        resultの末尾に 95 を追加する  # '_'
                        kを増やす
                    }
                }
                そうでなければ {
                    # Add single dash
                    resultの末尾に 45 を追加する  # '-'
                }

                # Skip the counted spaces
                i = 和(i, 差(space_count, 1))
            }
            そうでなければ {
                resultの末尾に char を追加する
            }
            iを増やす
        }
    }

    resultが答え
